mapper.select:
SELECT id, skill_id AS skillId, embedding_model AS embeddingModel, embedding_vector::text AS embeddingVector, routing_text AS routingText, status, remark, create_by AS createBy, create_time AS createTime, update_by AS updateBy, update_time AS updateTime, 1 - (embedding_vector <=> #{embedding}::vector) AS similarity FROM sys_skill_embedding WHERE status = 1
AND skill_id IN
#{id}
ORDER BY embedding_vector <=> #{embedding}::vector LIMIT #{limit}
